// Fabrique de flyweights
class ArbreFactory {
    private Map<String, ArbreFlyweight> cache = new HashMap<>();

    public ArbreFlyweight getArbre(String espece) {
        if (!cache.containsKey(espece))
            cache.put(espece, new ArbreFlyweight(espece+".obj", espece+".png", "vert"));
        return cache.get(espece);
    }
}
